import { Document, model, Schema } from 'mongoose';

/**
 * Interface representing a Group.
 */
export interface Group extends Document {
  name: string;
  description: string;
  adminId: string;
  members: string[];
  telegramChatId?: string;
  createdAt: Date;
}

/**
 * Mongoose schema for Group.
 */
const GroupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: String, required: true },
  members: [{ type: String, required: true }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model<Group>('Group', GroupSchema);

import { Document, model, Schema } from 'mongoose';

/**
 * Interfaces for recurrence options in a Task.
 */
interface Recurrence {
  type: 'daily' | 'weekly' | 'custom';
  daysOfWeek?: number[];
  time: string;
}

/**
 * Interface representing a Task.
 */
export interface Task extends Document {
  groupId: string;
  title: string;
  description: string;
  assignees: string[];
  rotationIndex: number;
  unavailableMembers: string[];
  recurrence: Recurrence;
  status: 'active' | 'paused';
}

/**
 * Mongoose schema for Task.
 */
const TaskSchema = new Schema<Task>({
  groupId: { type: String, required: true },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: [{ type: String, required: true }],
  rotationIndex: { type: Number, required: true },
  unavailableMembers: [{ type: String }],
  recurrence: {
    type: { type: String, enum: ['daily', 'weekly', 'custom'], required: true },
    daysOfWeek: [{ type: Number }],
    time: { type: String, required: true }
  },
  status: { type: String, enum: ['active', 'paused'], required: true }
});

export const TaskModel = model<Task>('Task', TaskSchema);
